import java.io.File;
import java.io.FileWriter;
import java.io.IOException;

import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly sanitize and escape user input
        String safeUserInput = StringEscapeUtils.escapeHtml4(userInput);

        try {
            File file = new File("output.html");
            FileWriter writer = new FileWriter(file);
            writer.write("<p>Welcome, " + safeUserInput + "</p>");
            writer.close();
            System.out.println("Output written to file successfully.");
        } catch (IOException e) {
            System.out.println("Error writing output to file: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
